import React, { useState } from "react";
import { Plus, X } from "lucide-react";

const timeSlots = [
  "06:00 AM", "07:00 AM", "08:00 AM", "09:00 AM", "10:00 AM", "11:00 AM",
  "12:00 PM", "01:00 PM", "02:00 PM", "03:00 PM", "04:00 PM", "05:00 PM",
  "06:00 PM", "07:00 PM", "08:00 PM", "09:00 PM", "10:00 PM"
];

const weekDays = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

const classTypes = [
  { name: "Yoga", color: "#8B5CF6" },
  { name: "HIIT", color: "#EF4444" },
  { name: "Spin", color: "#F59E0B" },
  { name: "CrossFit", color: "#10B981" },
  { name: "Boxing", color: "#EC4899" },
  { name: "Zumba", color: "#6366F1" },
  { name: "Pilates", color: "#14B8A6" },
];

const trainers = ["Sarah Johnson", "Mike Chen", "Emma Davis", "Alex Rodriguez", "James Wilson", "Tom Anderson", "Maria Garcia"];

export function ScheduleManager() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({
    className: "", instructor: "", date: "", time: "", duration: "", capacity: "",
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    console.log("Form submitted:", formData);
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Class Schedule Management</h1>
          <p className="text-gray-400 mt-1">View and manage weekly class schedule</p>
        </div>
        <button
          onClick={() => setIsModalOpen(true)}
          className="bg-[#39FF14] text-[#121212] px-6 py-3 rounded-lg font-bold hover:bg-[#2EE010] transition-colors flex items-center gap-2"
        >
          <Plus className="w-5 h-5" /> Create New Class
        </button>
      </div>

      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl overflow-x-auto">
        <div className="min-w-[1000px]">
          <div className="grid grid-cols-8 border-b border-[#2a2a2a] bg-[#121212]">
            <div className="p-4 border-r border-[#2a2a2a] text-sm text-gray-400">Time</div>
            {weekDays.map((day) => (
              <div key={day} className="p-4 border-r border-[#2a2a2a] text-center text-sm font-bold text-white">{day}</div>
            ))}
          </div>
          {timeSlots.map((time) => (
            <div key={time} className="grid grid-cols-8 border-b border-[#2a2a2a] min-h-[80px]">
              <div className="p-3 border-r border-[#2a2a2a] flex items-start text-xs text-gray-500">{time}</div>
              {weekDays.map((_, i) => (
                <div key={i} className="border-r border-[#2a2a2a] p-2 hover:bg-[#121212] transition-colors"></div>
              ))}
            </div>
          ))}
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-[#1a1a1a] border border-[#2a2a2a] w-full max-w-lg rounded-2xl p-8 relative">
            <button onClick={() => setIsModalOpen(false)} className="absolute top-4 right-4 text-gray-400 hover:text-white">
              <X size={24} />
            </button>
            <h2 className="text-xl font-bold text-white mb-6">Create New Class</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-2">
                <label className="text-sm text-gray-400">Class Type</label>
                <select 
                  className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-xl text-white outline-none focus:border-[#39FF14]"
                  onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setFormData({...formData, className: e.target.value})}
                >
                  <option value="">Select Type</option>
                  {classTypes.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <input type="date" className="bg-[#121212] border border-[#2a2a2a] p-3 rounded-xl text-white" onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormData({...formData, date: e.target.value})} />
                <input type="time" className="bg-[#121212] border border-[#2a2a2a] p-3 rounded-xl text-white" onChange={(e: React.ChangeEvent<HTMLInputElement>) => setFormData({...formData, time: e.target.value})} />
              </div>
              <button type="submit" className="w-full bg-[#39FF14] text-black font-bold py-4 rounded-xl mt-4">CREATE CLASS</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
